import { useState, useRef } from "react";
import { Card, PageTitle, Btn, Input, Textarea, Ic, ICONS, ErrBox } from "../components/UI";

// ── Step indicator ────────────────────────────────────────────────────────────
const Steps = ({ current, t }) => {
  const steps = ["Upload Photo", "Your Details", "Review & Generate", "Certificate"];
  return (
    <div style={{ display: "flex", alignItems: "center", marginBottom: 36 }}>
      {steps.map((s, i) => {
        const done    = i < current;
        const active  = i === current;
        const color   = done ? "#34d399" : active ? t.blue : t.muted;
        return (
          <div key={i} style={{ display: "flex", alignItems: "center", flex: i < steps.length - 1 ? 1 : 0 }}>
            <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, flexShrink: 0 }}>
              <div style={{
                width: 32, height: 32, borderRadius: "50%",
                background: done ? "#34d39920" : active ? `${t.blue}20` : t.surfaceUp,
                border: `2px solid ${color}`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 12, fontWeight: 800, color,
                transition: "all 0.3s",
              }}>
                {done ? "✓" : i + 1}
              </div>
              <span style={{ fontSize: 10, color, fontWeight: active ? 700 : 500, whiteSpace: "nowrap", letterSpacing: "0.03em" }}>{s}</span>
            </div>
            {i < steps.length - 1 && (
              <div style={{ flex: 1, height: 2, background: done ? "#34d39944" : t.border, margin: "0 8px", marginBottom: 20, transition: "background 0.3s" }} />
            )}
          </div>
        );
      })}
    </div>
  );
};

// ── Label ─────────────────────────────────────────────────────────────────────
const Label = ({ text, required, t }) => (
  <label style={{ fontSize: 11, color: t.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.07em", display: "block", marginBottom: 6 }}>
    {text} {required && <span style={{ color: t.blue }}>*</span>}
  </label>
);

// ── Field row for certificate preview ────────────────────────────────────────
const CertField = ({ label, value, mono, t, highlight }) => (
  <div style={{
    display: "flex", gap: 12, padding: "9px 14px",
    borderRadius: 7, background: highlight ? `${t.blue}0a` : t.surfaceUp,
    border: `1px solid ${highlight ? t.blue + "33" : t.border}`,
    fontSize: 12, alignItems: "flex-start",
  }}>
    <span style={{ color: t.muted, minWidth: 110, fontWeight: 700, flexShrink: 0, paddingTop: 1 }}>{label}</span>
    <span style={{ color: t.text, fontFamily: mono ? "monospace" : "inherit", wordBreak: "break-all", lineHeight: 1.5 }}>
      {value || <span style={{ color: t.muted, fontStyle: "italic" }}>—</span>}
    </span>
  </div>
);

// ── Main component ────────────────────────────────────────────────────────────
export default function Evidence({ t, toast, state, setState }) {
  // Use persisted state if passed, else local
  const usePersistedState = !!setState;
  const [_file,    _setFile]    = useState(null);
  const [_prev,    _setPrev]    = useState(null);
  const [_name,    _setName]    = useState("");
  const [_phone,   _setPhone]   = useState("");
  const [_address, _setAddress] = useState("");
  const [_brief,   _setBrief]   = useState("");
  const [_incDate, _setIncDate] = useState("");
  const [_policeStation, _setPoliceStation] = useState("");
  const [_cert,    _setCert]    = useState(null);
  const [_step,    _setStep]    = useState(0);

  // If persisted state is provided use it, else use local
  const s = usePersistedState ? state : {
    file: _file, prev: _prev, cert: _cert,
    name: _name, phone: _phone, address: _address,
    brief: _brief, incDate: _incDate, policeStation: _policeStation,
    step: _step,
  };
  const update = usePersistedState
    ? (key, val) => setState(prev => ({ ...prev, [key]: val }))
    : (key, val) => ({
        file: _setFile, prev: _setPrev, cert: _setCert,
        name: _setName, phone: _setPhone, address: _setAddress,
        brief: _setBrief, incDate: _setIncDate, policeStation: _setPoliceStation,
        step: _setStep,
      })[key]?.(val);

  const [load, setLoad] = useState(false);
  const [err,  setErr]  = useState(null);
  const fileRef = useRef();

  const step = s.step ?? 0;
  const setStep = v => update("step", v);

  const pickFile = (f) => {
    if (!f) return;
    update("file", f);
    update("cert", null);
    setErr(null);
    const rd = new FileReader();
    rd.onload = e => update("prev", e.target.result);
    rd.readAsDataURL(f);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    const f = e.dataTransfer.files[0];
    if (f && f.type.startsWith("image/")) pickFile(f);
  };

  const generate = async () => {
    setLoad(true); setErr(null);
    try {
      const fd = new FormData();
      fd.append("file",              s.file);
      fd.append("complainant_name",  s.name    || "Not provided");
      fd.append("complainant_phone", s.phone   || "");
      fd.append("complainant_address", s.address || "");
      fd.append("incident_brief",    s.brief   || "Evidence submitted via NyayaSetu");
      fd.append("incident_date",     s.incDate || "");
      fd.append("police_station",    s.policeStation || "");

      const r = await fetch("http://localhost:8001/api/evidence", { method: "POST", body: fd });
      if (!r.ok) {
        const errData = await r.json().catch(() => ({}));
        throw new Error(errData.detail || `Server error ${r.status}`);
      }
      const data = await r.json();
      update("cert", data);
      setStep(3);
      toast("Certificate generated ✓", "success");
    } catch (e) { setErr(e.message); toast(e.message, "error"); }
    finally { setLoad(false); }
  };

  const reset = () => {
    ["file","prev","cert","name","phone","address","brief","incDate","policeStation"].forEach(k => update(k, k === "step" ? 0 : null));
    update("step", 0);
    setErr(null);
  };

  const cert = s.cert;

  // SHA-256 display
  const hash = cert?.sha256_hash || cert?.sha256 || "";

  return (
    <div style={{ maxWidth: 820, margin: "0 auto", padding: "52px 24px", animation: "fadeUp 0.4s ease" }}>
      <PageTitle icon="camera" title="Evidence Certificate" badge="BSA §63"
        desc="Generate a court-admissible SHA-256 certificate for digital evidence under BSA Section 63. Fill in the details — we'll generate a complete certificate."
        t={t} />

      <Steps current={step} t={t} />

      {/* ── STEP 0: Upload ── */}
      {step === 0 && (
        <Card t={t}>
          <div style={{ marginBottom: 20 }}>
            <h3 style={{ fontSize: 15, fontWeight: 800, color: t.text, margin: "0 0 6px" }}>Upload the evidence photo</h3>
            <p style={{ fontSize: 13, color: t.sub, margin: 0, lineHeight: 1.7 }}>
              This can be a screenshot, a photo of damaged property, a WhatsApp message, or any digital image you want to certify.
              The SHA-256 hash is computed <strong style={{ color: t.text }}>before</strong> any processing.
            </p>
          </div>

          {s.prev ? (
            <div style={{ position: "relative", borderRadius: 12, overflow: "hidden", border: `1.5px solid ${t.border}`, marginBottom: 20 }}>
              <img src={s.prev} alt="preview" style={{ width: "100%", maxHeight: 320, objectFit: "contain", display: "block", background: t.bg }} />
              <div style={{ padding: "12px 16px", background: t.surfaceUp, borderTop: `1px solid ${t.border}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                  <p style={{ fontSize: 13, fontWeight: 700, color: t.text, margin: "0 0 2px" }}>{s.file?.name}</p>
                  <p style={{ fontSize: 11, color: t.muted, margin: 0 }}>{s.file ? (s.file.size / 1024).toFixed(1) + " KB · " + s.file.type : ""}</p>
                </div>
                <button onClick={() => { update("file", null); update("prev", null); setErr(null); }} style={{ background: "none", border: `1px solid ${t.border}`, borderRadius: 7, cursor: "pointer", color: t.sub, fontSize: 12, fontFamily: "inherit", fontWeight: 600, padding: "5px 12px" }}>
                  Change
                </button>
              </div>
            </div>
          ) : (
            <div
              onClick={() => fileRef.current.click()}
              onDragOver={e => e.preventDefault()}
              onDrop={handleDrop}
              style={{
                border: `2px dashed ${t.border}`, borderRadius: 12,
                padding: "52px 24px", textAlign: "center",
                cursor: "pointer", background: t.surfaceUp,
                transition: "all 0.15s", marginBottom: 20,
              }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = t.blue; e.currentTarget.style.background = `${t.blue}08`; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = t.border; e.currentTarget.style.background = t.surfaceUp; }}
            >
              <input ref={fileRef} type="file" accept=".jpg,.jpeg,.png,.webp" style={{ display: "none" }} onChange={e => pickFile(e.target.files[0])} />
              <div style={{ width: 52, height: 52, borderRadius: 14, background: `${t.blue}14`, border: `1px solid ${t.blue}22`, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px" }}>
                <Ic d={ICONS.upload} size={22} color={t.blue} />
              </div>
              <p style={{ fontSize: 14, fontWeight: 600, color: t.text, margin: "0 0 6px" }}>Drop image here or <span style={{ color: t.blue }}>browse</span></p>
              <p style={{ fontSize: 12, color: t.muted, margin: 0 }}>JPG, PNG, WebP · Screenshots, photos, chat exports</p>
            </div>
          )}

          {/* What counts as valid evidence */}
          <div style={{ padding: "14px 18px", borderRadius: 10, background: t.surfaceUp, border: `1px solid ${t.border}`, marginBottom: 20 }}>
            <p style={{ fontSize: 11, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "0 0 10px" }}>What counts as valid digital evidence</p>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
              {["📱 Screenshots of threatening messages", "📸 Photos of physical damage or injury", "💬 WhatsApp or email conversations", "🖥️ Social media posts or profile screenshots", "📄 Forged documents photographed", "🗂️ Any digital record relevant to the case"].map((item, i) => (
                <div key={i} style={{ fontSize: 12, color: t.sub, display: "flex", alignItems: "flex-start", gap: 6 }}>{item}</div>
              ))}
            </div>
          </div>

          <Btn onClick={() => setStep(1)} disabled={!s.file} t={t}>
            Continue <Ic d={ICONS.arrow} size={14} color="#fff" sw={2} />
          </Btn>
        </Card>
      )}

      {/* ── STEP 1: Your Details ── */}
      {step === 1 && (
        <Card t={t}>
          <div style={{ marginBottom: 24 }}>
            <h3 style={{ fontSize: 15, fontWeight: 800, color: t.text, margin: "0 0 6px" }}>Complainant details</h3>
            <p style={{ fontSize: 13, color: t.sub, margin: 0, lineHeight: 1.7 }}>
              These will be printed on the certificate. Name is required — other fields strengthen the certificate but are optional.
            </p>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <div>
              <Label text="Full Name" required t={t} />
              <Input value={s.name || ""} onChange={e => update("name", e.target.value)}
                placeholder="e.g. Rahul Sharma" t={t} />
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
              <div>
                <Label text="Phone Number" t={t} />
                <Input value={s.phone || ""} onChange={e => update("phone", e.target.value)}
                  placeholder="e.g. 9876543210" t={t} />
              </div>
              <div>
                <Label text="Incident Date" t={t} />
                <input
                  type="date"
                  value={s.incDate || ""}
                  onChange={e => update("incDate", e.target.value)}
                  style={{ background: t.surfaceUp, border: `1.5px solid ${t.border}`, borderRadius: 8, padding: "10px 14px", color: t.text, fontSize: 14, fontFamily: "inherit", outline: "none", width: "100%", boxSizing: "border-box" }}
                />
              </div>
            </div>

            <div>
              <Label text="Your Address" t={t} />
              <Input value={s.address || ""} onChange={e => update("address", e.target.value)}
                placeholder="e.g. Flat 4B, Andheri West, Mumbai 400058" t={t} />
            </div>

            <div>
              <Label text="Police Station (if FIR filed)" t={t} />
              <Input value={s.policeStation || ""} onChange={e => update("policeStation", e.target.value)}
                placeholder="e.g. Andheri Police Station, Mumbai" t={t} />
            </div>

            <div>
              <Label text="Incident Description" required t={t} />
              <Textarea value={s.brief || ""} onChange={e => update("brief", e.target.value)} rows={4}
                placeholder="Describe what happened in 2–3 sentences. Include date, location, and nature of incident. e.g. 'On 20 March 2026, I received threatening WhatsApp messages from an unknown number demanding money. I have preserved these screenshots as evidence.'"
                t={t} />
              <p style={{ fontSize: 11, color: t.muted, margin: "6px 0 0" }}>
                This appears verbatim in the certificate. Be precise — the certificate is a legal document.
              </p>
            </div>
          </div>

          <div style={{ display: "flex", gap: 10, marginTop: 24 }}>
            <button onClick={() => setStep(0)} style={{ background: "none", border: `1.5px solid ${t.border}`, borderRadius: 8, cursor: "pointer", color: t.sub, fontSize: 13, fontFamily: "inherit", fontWeight: 600, padding: "10px 20px" }}>← Back</button>
            <Btn onClick={() => setStep(2)} disabled={!s.name?.trim() || !s.brief?.trim()} t={t}>
              Review Details <Ic d={ICONS.arrow} size={14} color="#fff" sw={2} />
            </Btn>
          </div>
        </Card>
      )}

      {/* ── STEP 2: Review ── */}
      {step === 2 && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Preview panel */}
          <Card t={t}>
            <h3 style={{ fontSize: 15, fontWeight: 800, color: t.text, margin: "0 0 6px" }}>Review before generating</h3>
            <p style={{ fontSize: 13, color: t.sub, margin: "0 0 20px", lineHeight: 1.7 }}>
              The certificate will be generated with these details. Check everything carefully — the PDF cannot be edited after generation.
            </p>

            {/* Certificate preview mockup */}
            <div style={{ padding: "20px 22px", borderRadius: 12, border: `2px solid ${t.blue}33`, background: `${t.blue}06`, marginBottom: 20 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16, paddingBottom: 16, borderBottom: `1px solid ${t.border}` }}>
                <div style={{ width: 36, height: 36, borderRadius: 9, background: `${t.blue}18`, border: `1px solid ${t.blue}22`, display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <Ic d={ICONS.shield} size={16} color={t.blue} />
                </div>
                <div>
                  <p style={{ fontSize: 12, fontWeight: 800, color: t.text, margin: 0 }}>ELECTRONIC EVIDENCE CERTIFICATE</p>
                  <p style={{ fontSize: 10, color: t.muted, margin: 0 }}>Section 63, Bharatiya Sakshya Adhiniyam 2023</p>
                </div>
                <div style={{ marginLeft: "auto", padding: "3px 10px", borderRadius: 6, background: "#34d39920", border: "1px solid #34d39933", fontSize: 10, fontWeight: 700, color: "#34d399" }}>DRAFT PREVIEW</div>
              </div>

              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "0 0 4px" }}>II. Complainant</p>
                <CertField label="Name" value={s.name} t={t} highlight />
                <CertField label="Phone" value={s.phone || "Not provided"} t={t} />
                <CertField label="Address" value={s.address || "Not provided"} t={t} />

                <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "12px 0 4px" }}>III. Incident Details</p>
                <CertField label="Date" value={s.incDate || "Not specified"} t={t} />
                <CertField label="Description" value={s.brief} t={t} highlight />
                {s.policeStation && <CertField label="Police Station" value={s.policeStation} t={t} />}

                <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "12px 0 4px" }}>IV. Electronic Record</p>
                <CertField label="File Name" value={s.file?.name} t={t} />
                <CertField label="File Size" value={s.file ? (s.file.size / 1024).toFixed(1) + " KB" : ""} t={t} />
                <CertField label="File Type" value={s.file?.type} t={t} />
                <CertField label="SHA-256" value="Will be computed at generation time" mono t={t} />
              </div>
            </div>

            {/* Attached image thumbnail */}
            {s.prev && (
              <div style={{ display: "flex", gap: 12, alignItems: "center", padding: "12px 14px", borderRadius: 10, background: t.surfaceUp, border: `1px solid ${t.border}`, marginBottom: 16 }}>
                <img src={s.prev} alt="evidence" style={{ width: 56, height: 56, objectFit: "cover", borderRadius: 8, border: `1px solid ${t.border}`, flexShrink: 0 }} />
                <div>
                  <p style={{ fontSize: 13, fontWeight: 700, color: t.text, margin: "0 0 2px" }}>{s.file?.name}</p>
                  <p style={{ fontSize: 11, color: t.muted, margin: 0 }}>{s.file ? (s.file.size / 1024).toFixed(1) + " KB · " + s.file.type : ""}</p>
                </div>
              </div>
            )}

            {err && <ErrBox msg={err} t={t} />}

            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={() => setStep(1)} style={{ background: "none", border: `1.5px solid ${t.border}`, borderRadius: 8, cursor: "pointer", color: t.sub, fontSize: 13, fontFamily: "inherit", fontWeight: 600, padding: "10px 20px" }}>← Edit Details</button>
              <Btn onClick={generate} disabled={load} loading={load} t={t}>
                <Ic d={ICONS.shield} size={15} color="#fff" sw={2} />
                {load ? "Computing SHA-256 & generating…" : "Generate Certificate"}
              </Btn>
            </div>
          </Card>
        </div>
      )}

      {/* ── STEP 3: Certificate ── */}
      {step === 3 && cert && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16, animation: "fadeUp 0.4s ease" }}>
          {/* Success banner */}
          <div style={{ padding: "16px 20px", borderRadius: 12, background: "#052e1c", border: "1.5px solid #34d39944", display: "flex", alignItems: "center", gap: 14 }}>
            <div style={{ width: 40, height: 40, borderRadius: 10, background: "#34d39920", border: "1px solid #34d39933", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
              <Ic d={ICONS.check} size={18} color="#34d399" sw={2.5} />
            </div>
            <div>
              <p style={{ fontSize: 14, fontWeight: 800, color: "#34d399", margin: "0 0 3px" }}>Certificate Generated Successfully</p>
              <p style={{ fontSize: 12, color: "#34d39999", margin: 0 }}>SHA-256 computed before any processing · Chain of custody preserved · BSA Section 63 compliant</p>
            </div>
          </div>

          {/* Main certificate card */}
          <Card t={t}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20, paddingBottom: 16, borderBottom: `1px solid ${t.border}` }}>
              <div>
                <p style={{ fontSize: 15, fontWeight: 800, color: t.text, margin: "0 0 3px" }}>Electronic Evidence Certificate</p>
                <p style={{ fontSize: 11, color: t.muted, margin: 0 }}>Section 63, Bharatiya Sakshya Adhiniyam 2023</p>
              </div>
              <div style={{ textAlign: "right" }}>
                <p style={{ fontSize: 12, fontWeight: 700, color: t.blue, margin: "0 0 2px", fontFamily: "monospace" }}>
                  {cert.certificate_id ? `NS-${cert.certificate_id}` : cert.cert_id || "—"}
                </p>
                <p style={{ fontSize: 10, color: t.muted, margin: 0 }}>Certificate ID</p>
              </div>
            </div>

            {/* SHA-256 — the most important field */}
            <div style={{ padding: "16px 18px", borderRadius: 10, background: t.bg, border: `2px solid ${t.blue}33`, marginBottom: 16 }}>
              <p style={{ fontSize: 10, color: t.blue, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.08em", margin: "0 0 8px" }}>
                SHA-256 Hash — Chain of Custody
              </p>
              <p style={{ fontFamily: "monospace", fontSize: 12, color: t.text, wordBreak: "break-all", margin: 0, lineHeight: 1.7, letterSpacing: "0.02em" }}>
                {hash || "—"}
              </p>
            </div>

            {/* Two column details */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
              <div>
                <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "0 0 10px" }}>II. Complainant</p>
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  <CertField label="Name" value={cert.complainant_name || s.name} t={t} highlight />
                  <CertField label="Phone" value={cert.complainant_phone || s.phone || "—"} t={t} />
                  <CertField label="Address" value={cert.complainant_address || s.address || "—"} t={t} />
                </div>
              </div>
              <div>
                <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "0 0 10px" }}>III. Electronic Record</p>
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  <CertField label="File" value={cert.file_name || s.file?.name} t={t} />
                  <CertField label="Size" value={cert.file_size_bytes ? (cert.file_size_bytes / 1024).toFixed(1) + " KB" : s.file ? (s.file.size / 1024).toFixed(1) + " KB" : "—"} t={t} />
                  <CertField label="Certified at" value={cert.certification_timestamp || cert.timestamp || new Date().toLocaleString("en-IN")} t={t} />
                </div>
              </div>
            </div>

            {/* Incident details */}
            <div style={{ marginBottom: 16 }}>
              <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "0 0 10px" }}>IV. Incident Details</p>
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                <CertField label="Description" value={cert.incident_brief || s.brief} t={t} highlight />
                {(cert.incident_date || s.incDate) && <CertField label="Date" value={cert.incident_date || s.incDate} t={t} />}
                {(cert.police_station || s.policeStation) && <CertField label="Police Station" value={cert.police_station || s.policeStation} t={t} />}
              </div>
            </div>

            {/* EXIF data if available */}
            {(cert.gps_coordinates || cert.device_make || cert.capture_timestamp) && (
              <div style={{ marginBottom: 16 }}>
                <p style={{ fontSize: 10, color: t.muted, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.07em", margin: "0 0 10px" }}>V. EXIF Metadata (from photo)</p>
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  {cert.device_make    && <CertField label="Device" value={`${cert.device_make} ${cert.device_model || ""}`.trim()} t={t} />}
                  {cert.capture_timestamp && <CertField label="Photo taken" value={cert.capture_timestamp} t={t} />}
                  {cert.gps_coordinates && <CertField label="GPS" value={cert.gps_coordinates} t={t} />}
                </div>
              </div>
            )}

            {/* Verify instructions */}
            <div style={{ padding: "12px 16px", borderRadius: 9, background: t.surfaceUp, border: `1px solid ${t.border}` }}>
              <p style={{ fontSize: 11, color: t.muted, fontWeight: 700, margin: "0 0 6px" }}>HOW TO VERIFY THIS CERTIFICATE</p>
              <p style={{ fontSize: 12, color: t.sub, margin: "0 0 4px", lineHeight: 1.6 }}>
                Run this on the original file and compare with SHA-256 above:
              </p>
              <code style={{ fontSize: 11, color: t.text, display: "block", padding: "6px 10px", background: t.bg, borderRadius: 6, fontFamily: "monospace" }}>
                Linux/Mac: sha256sum {"<filename>"}<br />
                Windows: certutil -hashfile {"<filename>"} SHA256
              </code>
            </div>
          </Card>

          {/* Actions */}
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            {(cert.pdf_download_url || cert.pdf_url) && (
              <a
                href={`http://localhost:8001${cert.pdf_download_url || cert.pdf_url}`}
                target="_blank" rel="noreferrer"
                style={{ textDecoration: "none" }}
              >
                <Btn t={t} onClick={() => {}}>
                  <Ic d={ICONS.external} size={14} color="#fff" sw={2} />
                  Download PDF Certificate
                </Btn>
              </a>
            )}
            <button onClick={reset} style={{ background: "none", border: `1.5px solid ${t.border}`, borderRadius: 8, cursor: "pointer", color: t.sub, fontSize: 13, fontFamily: "inherit", fontWeight: 600, padding: "10px 20px" }}>
              + New Certificate
            </button>
          </div>

          {/* Legal note */}
          <div style={{ padding: "12px 16px", borderRadius: 10, background: t.amberDim || "#2d1f07", border: `1px solid ${(t.amber || "#fbbf24")}33`, display: "flex", gap: 10 }}>
            <Ic d={ICONS.alert} size={15} color={t.amber || "#fbbf24"} />
            <p style={{ fontSize: 12, color: t.amber || "#fbbf24", margin: 0, lineHeight: 1.7 }}>
              <strong>Important:</strong> Present this certificate together with the <strong>original unmodified file</strong> to the investigating officer or court. Do not crop, edit, or re-save the original after generating this certificate.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}
